function tableRow(builders, node) {
	const cells = [];
	if(node.content) {
		for(let i = 0; i < node.content.length; i++) {
			const cellNode = node.content[i];
			if(cellNode.type === "table_header" || cellNode.type === "table_cell") {
				cells.push(tableCellOrHeader(builders, cellNode));
			}
		}
	}
	return {
		type: "element",
		tag: "tr",
		children: cells
	};
