		const newFirstLine = newRawText.split("\n")[0] || newRawText;

		const pos = this.getPos();
		if(typeof pos !== "number") return;
		const tr = this.view.state.tr.setNodeMarkup(pos, null, {
			rawText: newRawText,
			firstLine: newFirstLine.trim(),
			parseTreeJson: null
		});
