function scanForClosingBrackets(str, start) {
	let pos = start;
	while(pos < str.length - 1) {
		const ch = str[pos];
		// Triple-double-quote delimiter: """..."""
		if(ch === '"' && str[pos + 1] === '"' && str[pos + 2] === '"') {
			pos += 3;
			while(pos < str.length - 2) {
				if(str[pos] === '"' && str[pos + 1] === '"' && str[pos + 2] === '"') {
					pos += 3;
					break;
				}
