		// Double-quote string
		if(ch === '"') {
			pos++;
			while(pos < str.length && str[pos] !== '"') {
				if(str[pos] === "\\") pos++; // skip escaped char
				pos++;
			}
			pos++; // skip closing quote
			continue;
		}
		// Single-quote string
		if(ch === "'") {
			pos++;
			while(pos < str.length && str[pos] !== "'") {
				if(str[pos] === "\\") pos++;
				pos++;
			}
			pos++;
			continue;
		}
