		label: helpers.lang("Duplicate", "Duplicate"),
		icon: "+",
		iconTiddler: "$:/core/images/clone-button",
		action: safeAction((pos, node) => {
			const tr = view.state.tr;
			const insertPos = pos + node.nodeSize;
