		label: helpers.lang("Delete", "Delete"),
		icon: "\u00D7",
		iconTiddler: "$:/core/images/delete-button",
		action: safeAction((pos, node) => {
			const tr = view.state.tr.delete(pos, pos + node.nodeSize);
