\rules only filteredtranscludeinline transcludeinline macrodef macrocallinline macrocallblock

.tc-prosemirror-drag-handle {
	color: <<colour muted-foreground>>;
}

.tc-prosemirror-drag-handle:hover {
	background: <<colour tiddler-editor-fields-even>>;
	color: <<colour foreground>>;
}

.tc-prosemirror-block-menu {
	background: <<colour tiddler-background>>;
	border-color: <<colour tiddler-editor-border>>;
}

.tc-prosemirror-block-menu-search {
	border-color: <<colour tiddler-editor-border>>;
	background: <<colour tiddler-editor-background>>;
	color: <<colour foreground>>;
}

.tc-prosemirror-block-menu-search:focus {
	border-color: <<colour primary>>;
}

.tc-prosemirror-block-menu-group {
	color: <<colour muted-foreground>>;
}

.tc-prosemirror-block-menu-item {
	color: <<colour foreground>>;
}

.tc-prosemirror-block-menu-item:hover,
.tc-prosemirror-block-menu-item-focused {
	background: <<colour tiddler-editor-fields-even>>;
}

.tc-prosemirror-block-menu-item-icon {
	color: <<colour muted-foreground>>;
}

/* Drag handle structural styles — colours in ui.color.tid */
.tc-prosemirror-drag-handle {
	display: flex;
	align-items: center;
	justify-content: center;
	width: 20px;
	height: 24px;
	cursor: grab;
	font-size: 14px;
	border-radius: 3px;
	user-select: none;
	opacity: 0.7;
	transition: opacity 0.15s, background 0.15s;
}

.tc-prosemirror-drag-handle:hover {
	opacity: 1;
}

.tc-prosemirror-drag-handle:active {
	cursor: grabbing;
}

.tc-prosemirror-block-menu {
	border: 1px solid transparent;
	border-radius: 6px;
	box-shadow: 0 4px 16px rgba(0,0,0,0.15);
	min-width: 180px;
	max-width: 260px;
	max-height: 320px;
	overflow-y: auto;
	padding: 4px 0;
	font-size: 0.9em;
}

.tc-prosemirror-block-menu-search {
	display: block;
	width: calc(100% - 16px);
	margin: 4px 8px 6px;
	padding: 5px 8px;
	border: 1px solid transparent;
	border-radius: 4px;
	font-size: 0.9em;
	outline: none;
}

.tc-prosemirror-block-menu-group {
	padding: 4px 12px 2px;
	font-size: 0.8em;
	font-weight: bold;
	text-transform: uppercase;
	letter-spacing: 0.05em;
	user-select: none;
}

.tc-prosemirror-block-menu-items {
	max-height: 240px;
	overflow-y: auto;
}

.tc-prosemirror-block-menu-item {
	display: flex;
	align-items: center;
	gap: 8px;
	padding: 5px 12px;
	cursor: pointer;
	border-radius: 0;
	transition: background 0.1s;
}

.tc-prosemirror-block-menu-item-icon {
	width: 20px;
	text-align: center;
	flex-shrink: 0;
	font-size: 0.95em;
}

.tc-prosemirror-block-menu-item-label {
	flex: 1;
	white-space: nowrap;
	overflow: hidden;
	text-overflow: ellipsis;
}

.tc-prosemirror-hidden {
	display: none !important;
}

html[dir="rtl"] .tc-prosemirror-drag-handle {
	left: auto;
	right: -24px;
}

html[dir="rtl"] .tc-prosemirror-block-menu {
	direction: rtl;
	text-align: right;
}

$:/plugins/tiddlywiki/prosemirror/featur.text:
/*\
title: $:/plugins/tiddlywiki/prosemirror/features/editor-placeholder.js
type: application/javascript
module-type: library

Editor-wide placeholder behavior for an empty ProseMirror document.

\*/

"use strict";

const Plugin = require("prosemirror-state").Plugin;

function defaultIsEmpty(state) {
	return state.doc.childCount === 1 && state.doc.firstChild && state.doc.firstChild.isTextblock && state.doc.firstChild.content.size === 0;
}

function placeholderPlugin(options = {}) {
	const text = typeof options.text === "string" ? options.text : "Type / for commands";
	const isEmpty = typeof options.isEmpty === "function" ? options.isEmpty : defaultIsEmpty;

	return new Plugin({
		props: {
			decorations(state) {
				if(!isEmpty(state)) {
					return null;
				}
				return null;
			}
		},
		view(view) {
			const dom = view.dom;
			const update = () => {
				const empty = isEmpty(view.state);
				if(empty) {
					dom.classList.add("tw-prosemirror-empty");
					dom.setAttribute("data-placeholder", text);
				} else {
					dom.classList.remove("tw-prosemirror-empty");
					dom.removeAttribute("data-placeholder");
				}
			};
			update();
			return {
				update,
				destroy() {
					dom.classList.remove("tw-prosemirror-empty");
					dom.removeAttribute("data-placeholder");
				}
			};
		}
	});
}

module.exports = {
	placeholderPlugin
};

