.tw-slash-menu-item-label {
	flex: 1;
	font-weight: 500;
}

.tw-slash-menu-item-description {
	font-size: 0.8em;
	line-height: 1.3;
}

.tw-slash-menu-item-text {
	display: flex;
	flex-direction: column;
	gap: 1px;
}

.tw-slash-menu-placeholder {
	text-align: center;
	padding: 16px 12px;
	font-style: italic;
}

.tw-slash-menu-group-title {
	font-size: 13px;
	font-weight: bold;
	padding: 8px 12px 2px 12px;
	margin-top: 8px;
	margin-bottom: 2px;
	border-bottom: 1px solid transparent;
	letter-spacing: 0.5px;
}

html[dir="rtl"] .tw-slash-menu-root {
	direction: rtl;
	text-align: right;
}

