.ProseMirror {
  position: relative;
}

.ProseMirror.tw-prosemirror-empty::before {
  content: attr(data-placeholder);
  color: var(--tc-muted-foreground, #6b6b6b);
  pointer-events: none;
  float: left;
  height: 0;
}

.tc-prosemirror-mount {
  /* Mount point for the ProseMirror wrapper and editor */
}

.tc-prosemirror-wrapper {
  display: block;
  overflow: hidden;
}

/* Prevent headings from overflowing the editor boundaries */
.ProseMirror h1, .ProseMirror h2, .ProseMirror h3,
.ProseMirror h4, .ProseMirror h5, .ProseMirror h6 {
  overflow-wrap: break-word;
  word-break: break-word;
  max-width: 100%;
}

.ProseMirror {
  word-wrap: break-word;
  white-space: pre-wrap;
  white-space: break-spaces;
  -webkit-font-variant-ligatures: none;
  font-variant-ligatures: none;
  font-feature-settings: "liga" 0; /* the above doesn't seem to work in Edge */
}

.ProseMirror pre {
  white-space: pre-wrap;
}

.ProseMirror li {
  position: relative;
}

.ProseMirror-hideselection *::selection { background: transparent; color: currentColor; }
.ProseMirror-hideselection *::-moz-selection { background: transparent; color: currentColor; }
.ProseMirror-hideselection { caret-color: transparent; }

/* See https://github.com/ProseMirror/prosemirror/issues/1421#issuecomment-1759320191 */
.ProseMirror [draggable][contenteditable=false] { user-select: text }

.ProseMirror-selectednode {
  outline: 2px solid #8cf;
}

/* Make sure li selections wrap around markers */

li.ProseMirror-selectednode {
  outline: none;
}

li.ProseMirror-selectednode:after {
  content: "";
  position: absolute;
  left: -32px;
  right: -2px; top: -2px; bottom: -2px;
  border: 2px solid #8cf;
  pointer-events: none;
}

/* Protect against generic img rules */

img.ProseMirror-separator {
  display: inline !important;
  border: none !important;
  margin: 0 !important;
}

