			imageTiddlerFields(),
			{ title: "Second Image.svg", type: "image/svg+xml", text: "<svg xmlns=\"http://www.w3.org/2000/svg\" width=\"32\" height=\"24\"><rect width=\"32\" height=\"24\" fill=\"#3b82f6\"/></svg>" }
		];
