		await page.waitForTimeout(600);
		const saved = await page.evaluate((t) => $tw.wiki.getTiddlerText(t, ""), exampleTitle);
		expect(saved).toContain("Second Image.svg");
		expect(saved).not.toContain("Motovun Jack.jpg");
