/*\
title: test-prosemirror-editor-mapping.js
type: application/javascript
tags: [[$:/tags/test-spec]]

Tests for editor type fallback integration with ProseMirror mapping.
\*/

"use strict";

describe("ProseMirror editor mapping fallback", function() {
	function withBrowserFlag(value, callback) {
		var originalBrowser = $tw.browser;
		$tw.browser = value;
		try {
			callback();
		} finally{
			$tw.browser = originalBrowser;
		}
	}

	it("should fall back to text editor outside the browser when mapped to prosemirror", function() {
		var EditWidget = require("$:/core/modules/widgets/edit.js").edit;
		var wiki = new $tw.Wiki();
		wiki.addTiddler({
			title: "$:/config/EditorTypeMappings/text/vnd.tiddlywiki",
			text: "prosemirror"
		});
		wiki.addTiddler({
			title: "MappingFallbackTest",
			text: "Hello world",
			type: "text/vnd.tiddlywiki"
		});

		var widget = {
			wiki: wiki,
			editTitle: "MappingFallbackTest",
			editField: "text"
		};

		withBrowserFlag(false,function() {
			expect(EditWidget.prototype.getEditorType.call(widget)).toBe("text");
		});
	});

	it("should fall back to text editor in the browser when a mapped parser is unavailable", function() {
		var EditWidget = require("$:/core/modules/widgets/edit.js").edit;
		var wiki = new $tw.Wiki();
		wiki.addTiddler({
			title: "$:/config/EditorTypeMappings/application/x-unknown",
			text: "prosemirror"
		});
		wiki.addTiddler({
			title: "MissingParserFallbackTest",
			text: "Hello world",
			type: "application/x-unknown"
		});

		var widget = {
			wiki: wiki,
			editTitle: "MissingParserFallbackTest",
			editField: "text"
		};

		withBrowserFlag(true,function() {
			expect(EditWidget.prototype.getEditorType.call(widget)).toBe("text");
		});
	});

	it("should use prosemirror in the browser for markdown when the parser is available", function() {
		var EditWidget = require("$:/core/modules/widgets/edit.js").edit;
		var wiki = new $tw.Wiki();
		wiki.addTiddler({
			title: "$:/config/EditorTypeMappings/text/markdown",
			text: "prosemirror"
		});
		wiki.addTiddler({
			title: "MarkdownMappingTest",
			text: "# Heading",
			type: "text/markdown"
		});

		var widget = {
			wiki: wiki,
			editTitle: "MarkdownMappingTest",
			editField: "text"
		};

		withBrowserFlag(true,function() {
			expect($tw.Wiki.parsers["text/markdown"]).toBeTruthy();
			expect(EditWidget.prototype.getEditorType.call(widget)).toBe("prosemirror");
		});
	});
});

test-prosemirror-engine-ops.js.text:
/*\
title: test-prosemirror-engine-ops.js
type: application/javascript
tags: [[$:/tags/test-spec]]

Tests for ProseMirror engine text operation mapping logic.
These run in node without a real EditorView, testing the helper methods.

\*/

"use strict";

describe("ProseMirror engine operation mapping", () => {

	let buildSchema, ProseMirrorEngine;
	try {
		// engine.js imports browser-only prosemirror-view at the top level,
		// so in Node it will throw. We still test buildSchema and mark mapping
		// by importing the engine module which re-exports buildSchema.
		const mod = require("$:/plugins/tiddlywiki/prosemirror/core/engine.js");
		buildSchema = mod.buildSchema;
		ProseMirrorEngine = mod.ProseMirrorEngine;
	} catch(e) {
		// If engine.js cannot be loaded (missing prosemirror-view in Node),
		// try buildSchema from a lighter module or skip gracefully.
		try {
			// buildSchema only needs prosemirror-model and prosemirror-schema-basic.
			require("prosemirror-model").Schema;
			// If we got here, prosemirror-model is available but engine.js failed
			// due to prosemirror-view. Skip the tests.
		} catch(e2) {
			// No prosemirror at all, skip
		}
		return;
	}

	// Test buildSchema
	describe("buildSchema", () => {

		it("should export buildSchema function", () => {
			expect(typeof buildSchema).toBe("function");
		});

		it("should return a ProseMirror schema with expected node types", () => {
			const schema = buildSchema();
			expect(schema).toBeDefined();
			expect(schema.nodes).toBeDefined();
			expect(schema.nodes.doc).toBeDefined();
			expect(schema.nodes.paragraph).toBeDefined();
			expect(schema.nodes.heading).toBeDefined();
			expect(schema.nodes.code_block).toBeDefined();
			expect(schema.nodes.blockquote).toBeDefined();
			expect(schema.nodes.horizontal_rule).toBeDefined();
			expect(schema.nodes.image).toBeDefined();
			expect(schema.nodes.hard_break).toBeDefined();
			expect(schema.nodes.list).toBeDefined();
		});

		it("should have custom block types (pragma_block, opaque_block)", () => {
			const schema = buildSchema();
			expect(schema.nodes.pragma_block).toBeDefined();
			expect(schema.nodes.opaque_block).toBeDefined();
		});

		it("should have extended marks (underline, strike, superscript, subscript)", () => {
			const schema = buildSchema();
			expect(schema.marks.strong).toBeDefined();
			expect(schema.marks.em).toBeDefined();
			expect(schema.marks.code).toBeDefined();
			expect(schema.marks.link).toBeDefined();
			expect(schema.marks.underline).toBeDefined();
			expect(schema.marks.strike).toBeDefined();
			expect(schema.marks.superscript).toBeDefined();
			expect(schema.marks.subscript).toBeDefined();
		});

		it("should set image node attrs with tw-specific fields", () => {
			const schema = buildSchema();
			const imageSpec = schema.nodes.image.spec;
			expect(imageSpec.attrs.twSource).toBeDefined();
			expect(imageSpec.attrs.twKind).toBeDefined();
			expect(imageSpec.attrs.twTooltip).toBeDefined();
			expect(imageSpec.attrs.width).toBeDefined();
			expect(imageSpec.attrs.height).toBeDefined();
		});

		it("should mark superscript and subscript as mutually exclusive", () => {
			const schema = buildSchema();
			expect(schema.marks.superscript.spec.excludes).toBe("subscript");
			expect(schema.marks.subscript.spec.excludes).toBe("superscript");
		});
	});

	// Test _wrapSelectionToMark mapping (we instantiate a mock engine)
	describe("_wrapSelectionToMark mapping", () => {

		// Create a minimal mock engine to test the prototype method
		const proto = {};
		// Copy the method if it exists on ProseMirrorEngine prototype
		if(ProseMirrorEngine && ProseMirrorEngine.prototype._wrapSelectionToMark) {
			proto._wrapSelectionToMark = ProseMirrorEngine.prototype._wrapSelectionToMark;
		}

		if(proto._wrapSelectionToMark) {
			it("should map bold prefix/suffix to 'strong'", () => {
				expect(proto._wrapSelectionToMark("''", "''")).toBe("strong");
			});

			it("should map italic prefix/suffix to 'em'", () => {
				expect(proto._wrapSelectionToMark("//", "//")).toBe("em");
			});

			it("should map underline prefix/suffix to 'underline'", () => {
				expect(proto._wrapSelectionToMark("__", "__")).toBe("underline");
			});

			it("should map strikethrough prefix/suffix to 'strike'", () => {
				expect(proto._wrapSelectionToMark("~~", "~~")).toBe("strike");
			});

			it("should map superscript prefix/suffix to 'superscript'", () => {
				expect(proto._wrapSelectionToMark("^^", "^^")).toBe("superscript");
			});

			it("should map subscript prefix/suffix to 'subscript'", () => {
				expect(proto._wrapSelectionToMark(",,", ",,")).toBe("subscript");
			});

			it("should map backtick prefix/suffix to 'code'", () => {
				expect(proto._wrapSelectionToMark("`", "`")).toBe("code");
			});

			it("should return null for non-matching prefix/suffix", () => {
				expect(proto._wrapSelectionToMark("[[", "]]")).toBeNull();
				expect(proto._wrapSelectionToMark("{{", "}}")).toBeNull();
				expect(proto._wrapSelectionToMark("<<<", "<<<")).toBeNull();
			});

			it("should return null for asymmetric prefix/suffix", () => {
				expect(proto._wrapSelectionToMark("''", "//")).toBeNull();
			});

			it("should return null for null/empty args", () => {
				expect(proto._wrapSelectionToMark(null, null)).toBeNull();
				expect(proto._wrapSelectionToMark("", "")).toBeNull();
			});
		}
	});
});

test-prosemirror-incremental-sync.js.text:
/*\
title: test-prosemirror-incremental-sync.js
type: application/javascript
tags: [[$:/tags/test-spec]]

Unit tests for the incremental diff-based sync mechanism.
Tests Fragment.findDiffStart/findDiffEnd and ReplaceStep logic
used by applyExternalText() in engine.js and widget.js.

\*/

"use strict";

describe("ProseMirror incremental sync — diff calculation", () => {

	let buildSchema;
	let replaceChangedContent;
	let schema;

	try {
		require("prosemirror-model");
		buildSchema = require("$:/plugins/tiddlywiki/prosemirror/core/schema.js").buildSchema;
		replaceChangedContent = require("$:/plugins/tiddlywiki/prosemirror/core/incremental-sync.js").replaceChangedContent;
	} catch(e) {
		return;
	}

	beforeEach(() => {
		schema = buildSchema();
	});

	// Helper: create a doc node from JSON
	function makeDoc(json) {
		return schema.nodeFromJSON(json);
	}

	// Helper: create a simple paragraph doc
	function paraDoc(...texts) {
		return makeDoc({
			type: "doc",
			content: texts.map((text) => (text === ""
				? { type: "paragraph" }
				: { type: "paragraph", content: [{ type: "text", text: text }] })
			)
		});
	}

	// Helper: apply the external-sync diff between two docs
	function applyDiff(oldDoc, newDoc) {
		const diff = replaceChangedContent({
			replace(from, to, slice) {
				return oldDoc.replace(from, to, slice);
			}
		}, oldDoc, newDoc);
		return diff.changed ? diff.transaction : oldDoc;
	}

	// ─── findDiffStart / findDiffEnd ────────────────────────────────

	describe("findDiffStart", () => {

		it("should return null for identical documents", () => {
			const a = paraDoc("Hello");
			const b = paraDoc("Hello");
			expect(a.content.findDiffStart(b.content)).toBeNull();
		});

		it("should return null for identical multi-paragraph docs", () => {
			const a = paraDoc("Hello", "World");
			const b = paraDoc("Hello", "World");
			expect(a.content.findDiffStart(b.content)).toBeNull();
		});

		it("should detect appended paragraph", () => {
			const a = paraDoc("Hello");
			const b = paraDoc("Hello", "World");
			const diffStart = a.content.findDiffStart(b.content);
			// Position after first paragraph (nodeSize = text.length + 2)
			expect(diffStart).toBe(a.content.size);
		});

		it("should detect changed text content", () => {
			const a = paraDoc("Hello World");
			const b = paraDoc("Hello Earth");
			const diffStart = a.content.findDiffStart(b.content);
			// After "Hello " inside the paragraph
			expect(diffStart).toBeGreaterThan(1); // After para open tag
			expect(diffStart).toBeLessThan(a.content.size - 1); // Before para close tag
		});

		it("should detect inserted paragraph in the middle", () => {
			const a = paraDoc("Hello", "World");
			const b = paraDoc("Hello", "!", "World");
			const diffStart = a.content.findDiffStart(b.content);
			// Should be after first paragraph
			expect(diffStart).toBeGreaterThan(0);
			expect(diffStart).toBeLessThan(a.content.size);
		});

		it("should detect removed paragraph", () => {
			const a = paraDoc("A", "B", "C");
			const b = paraDoc("A", "C");
			const diffStart = a.content.findDiffStart(b.content);
			expect(diffStart).toBeGreaterThan(0);
		});
	});

	describe("findDiffEnd", () => {

		it("should return null for identical documents", () => {
			const a = paraDoc("Hello");
			const b = paraDoc("Hello");
			expect(a.content.findDiffEnd(b.content)).toBeNull();
		});

		it("should find common suffix when prepending", () => {
			const a = paraDoc("Hello");
			const b = paraDoc("!", "Hello");
			const diffEnd = a.content.findDiffEnd(b.content);
			expect(diffEnd).toBeDefined();
			expect(diffEnd.a).toBe(0);
		});

		it("should find common suffix for middle insertion", () => {
			const a = paraDoc("Hello", "World");
			const b = paraDoc("Hello", "!", "World");
			const diffEnd = a.content.findDiffEnd(b.content);
			expect(diffEnd).toBeDefined();
			// Common suffix "World" paragraph — position is content-relative
			expect(diffEnd.a).toBeGreaterThan(0);
			expect(diffEnd.a).toBeLessThan(a.content.size);
		});
	});

	// ─── Incremental diff application ──────────────────────────────

	describe("applyDiff", () => {

		it("should handle no-op (identical docs)", () => {
			const oldDoc = paraDoc("Hello World");
			const newDoc = paraDoc("Hello World");
			const result = applyDiff(oldDoc, newDoc);
			expect(result.eq(oldDoc)).toBe(true);
		});

		it("should append a new paragraph at the end", () => {
			const oldDoc = paraDoc("Hello World");
			const newDoc = paraDoc("Hello World", "");
			const result = applyDiff(oldDoc, newDoc);
			expect(result.childCount).toBe(2);
			expect(result.child(0).textContent).toBe("Hello World");
			expect(result.child(1).textContent).toBe("");
		});

		it("should append a paragraph with text", () => {
			const oldDoc = paraDoc("Hello");
			const newDoc = paraDoc("Hello", "World");
			const result = applyDiff(oldDoc, newDoc);
			expect(result.childCount).toBe(2);
			expect(result.child(1).textContent).toBe("World");
		});

		it("should insert a paragraph in the middle", () => {
			const oldDoc = paraDoc("Hello", "World");
			const newDoc = paraDoc("Hello", "!", "World");
			const result = applyDiff(oldDoc, newDoc);
			expect(result.childCount).toBe(3);
			expect(result.child(0).textContent).toBe("Hello");
			expect(result.child(1).textContent).toBe("!");
			expect(result.child(2).textContent).toBe("World");
		});

		it("should remove a paragraph from the middle", () => {
			const oldDoc = paraDoc("A", "B", "C");
			const newDoc = paraDoc("A", "C");
			const result = applyDiff(oldDoc, newDoc);
			expect(result.childCount).toBe(2);
			expect(result.child(0).textContent).toBe("A");
			expect(result.child(1).textContent).toBe("C");
		});

		it("should change text within a paragraph", () => {
			const oldDoc = paraDoc("Hello World");
			const newDoc = paraDoc("Hello Earth");
			const result = applyDiff(oldDoc, newDoc);
			expect(result.childCount).toBe(1);
			expect(result.child(0).textContent).toBe("Hello Earth");
		});

		it("should handle complete replacement", () => {
			const oldDoc = paraDoc("Old content");
			const newDoc = paraDoc("New content");
			const result = applyDiff(oldDoc, newDoc);
			expect(result.childCount).toBe(1);
			expect(result.child(0).textContent).toBe("New content");
		});

		it("should preserve paragraphs that are not changed", () => {
			const oldDoc = paraDoc("A", "B", "C", "D", "E");
			const newDoc = paraDoc("A", "B", "X", "D", "E");
			const result = applyDiff(oldDoc, newDoc);
			expect(result.childCount).toBe(5);
			expect(result.child(0).textContent).toBe("A");
			expect(result.child(1).textContent).toBe("B");
			expect(result.child(2).textContent).toBe("X");
			expect(result.child(3).textContent).toBe("D");
			expect(result.child(4).textContent).toBe("E");
		});

		it("should handle multiple empty paragraphs", () => {
			const oldDoc = paraDoc("Hello", "", "", "World");
			const newDoc = paraDoc("Hello", "", "", "World");
			const result = applyDiff(oldDoc, newDoc);
			expect(result.eq(oldDoc)).toBe(true);
		});

		it("should add empty paragraphs (preserves user-created empty lines)", () => {
			const oldDoc = paraDoc("Hello", "World");
			const newDoc = paraDoc("Hello", "", "", "World");
			const result = applyDiff(oldDoc, newDoc);
			expect(result.childCount).toBe(4);
			expect(result.child(0).textContent).toBe("Hello");
			expect(result.child(1).textContent).toBe("");
			expect(result.child(2).textContent).toBe("");
			expect(result.child(3).textContent).toBe("World");
		});

		it("should append without creating a reversed replacement range", () => {
			const oldDoc = paraDoc("A");
			const newDoc = paraDoc("A", "B");
			let capturedRange = null;
			const diff = replaceChangedContent({
				replace(from, to, slice) {
					capturedRange = { from: from, to: to, size: slice.size };
					return oldDoc.replace(from, to, slice);
				}
			}, oldDoc, newDoc);
			expect(diff.changed).toBe(true);
			expect(capturedRange.from).toBe(capturedRange.to);
			expect(capturedRange.size).toBeGreaterThan(0);
		});

		it("should delete without creating a reversed replacement range", () => {
			const oldDoc = paraDoc("A", "B", "C");
			const newDoc = paraDoc("A", "C");
			let capturedRange = null;
			const diff = replaceChangedContent({
				replace(from, to, slice) {
					capturedRange = { from: from, to: to, size: slice.size };
					return oldDoc.replace(from, to, slice);
				}
			}, oldDoc, newDoc);
			expect(diff.changed).toBe(true);
			expect(capturedRange.from).toBeLessThanOrEqual(capturedRange.to);
			expect(capturedRange.size).toBe(0);
		});
	});

	// ─── Serialization roundtrip comparison ────────────────────────

	describe("roundtrip echo detection", () => {

		let wikiAstToProseMirrorAst, wikiAstFromProseMirrorAst;

		try {
			wikiAstToProseMirrorAst = require("$:/plugins/tiddlywiki/prosemirror/ast/to-prosemirror.js").to;
			wikiAstFromProseMirrorAst = require("$:/plugins/tiddlywiki/prosemirror/ast/from-prosemirror.js").from;
		} catch(e) {
			return;
		}

		function parseToPMDoc(wikitext) {
			const wikiAst = $tw.wiki.parseText("text/vnd.tiddlywiki", wikitext, { preserveBlankLines: true }).tree;
			const pmAst = wikiAstToProseMirrorAst(wikiAst, { sourceText: wikitext });
			return schema.nodeFromJSON(pmAst);
		}

		function serializePMDoc(doc) {
			const content = doc.toJSON();
			const wikiAst = wikiAstFromProseMirrorAst(content);
			return $tw.utils.serializeWikitextParseTree(wikiAst);
		}

		it("should tolerate legacy parsers without blankline nodes", () => {
			const legacyAst = $tw.wiki.parseText("text/vnd.tiddlywiki", "Hello\n\n\nWorld", { preserveBlankLines: false }).tree;
			const pmAst = wikiAstToProseMirrorAst(legacyAst, { sourceText: "Hello\n\n\nWorld" });

			expect(legacyAst.map((node) => node.rule)).toEqual(["parseblock", "parseblock"]);
			expect(pmAst.content.map((node) => node.type)).toEqual(["paragraph", "paragraph"]);
			expect(schema.nodeFromJSON(pmAst).childCount).toBe(2);
		});

		it("should preserve empty paragraphs through wiki text roundtrip", () => {
			const pmDoc = paraDoc("Hello World", "");
			const lastSavedJSON = pmDoc.toJSON();

			const serialized = serializePMDoc(pmDoc);
			const reparsedAst = $tw.wiki.parseText("text/vnd.tiddlywiki", serialized, { preserveBlankLines: true }).tree;
			const reparsedPMAst = wikiAstToProseMirrorAst(reparsedAst, { sourceText: serialized });

			expect(JSON.stringify(reparsedPMAst)).toEqual(JSON.stringify(lastSavedJSON));
		});

		it("should detect genuine external change vs echo", () => {
			// Original: "Hello World"
			const original = parseToPMDoc("Hello World");
			const lastSavedJSON = original.toJSON();

			// External agent changes to "Hello Earth"
			const modified = parseToPMDoc("Hello Earth");
			const modifiedSerialized = serializePMDoc(modified);
			const reparsedAst = $tw.wiki.parseText("text/vnd.tiddlywiki", modifiedSerialized, { preserveBlankLines: true }).tree;
			const reparsedPMAst = wikiAstToProseMirrorAst(reparsedAst, { sourceText: modifiedSerialized });

			// Should NOT match — genuine change
			expect(JSON.stringify(reparsedPMAst)).not.toEqual(JSON.stringify(lastSavedJSON));
		});
	});
});

test-prosemirror-inputrules.js.text:
/*\
title: test-prosemirror-inputrules.js
type: application/javascript
tags: [[$:/tags/test-spec]]

Tests for ProseMirror input rules (buildInputRules).
These run in Node and verify that wikilink and other inline
input rules are registered in the returned plugin.

\*/

"use strict";

describe("ProseMirror input rules", () => {

	let buildInputRules, buildWikitextInlineRules, WIKITEXT_INLINE_MARK_RULES, buildSchema;
	try {
		const inputRulesMod = require("$:/plugins/tiddlywiki/prosemirror/core/inputrules.js");
		buildInputRules = inputRulesMod.buildInputRules;
		buildWikitextInlineRules = inputRulesMod.buildWikitextInlineRules;
		WIKITEXT_INLINE_MARK_RULES = inputRulesMod.WIKITEXT_INLINE_MARK_RULES;
		const schemaMod = require("$:/plugins/tiddlywiki/prosemirror/core/engine.js");
		buildSchema = schemaMod.buildSchema;
	} catch(e) {
		// Skip if any prosemirror dependency is unavailable in Node
		return;
	}

	it("should export buildInputRules function", () => {
		expect(typeof buildInputRules).toBe("function");
	});

	it("should return a plugin with rules array", () => {
		const schema = buildSchema();
		const plugin = buildInputRules(schema);
		expect(plugin).toBeDefined();
		expect(plugin.spec).toBeDefined();
		expect(plugin.spec.isInputRules).toBe(true);
	});

	it("should include wikilink input rules when schema has link mark", () => {
		const schema = buildSchema();
		const plugin = buildInputRules(schema);
		// Access the internal rules via the plugin spec props
		const handleTextInput = plugin.spec.props && plugin.spec.props.handleTextInput;
		expect(typeof handleTextInput).toBe("function");
	});

	it("should not include wikilink rules when schema lacks link mark", () => {
		const schema = buildSchema();
		// Create a schema without link mark by updating the spec
		const { Schema } = require("prosemirror-model");
		const nodes = schema.spec.nodes;
		const marks = schema.spec.marks.remove("link");
		const schemaNoLink = new Schema({ nodes, marks });
		const plugin = buildInputRules(schemaNoLink);
		expect(plugin).toBeDefined();
		expect(plugin.spec.isInputRules).toBe(true);
	});

	describe("wikilink regex patterns", () => {
		const simplePattern = /(?<!\[)\[\[([^\[\]|]+)\]\]$/;
		const pipePattern = /(?<!\[)\[\[([^\[\]|]+)\|([^\[\]|]+)\]\]$/;

		it("should match [[Target]]", () => {
			const match = simplePattern.exec("abc [[MyTiddler]]");
			expect(match).not.toBeNull();
			expect(match[1]).toBe("MyTiddler");
		});

		it("should match [[Display|Target]]", () => {
			const match = pipePattern.exec("abc [[here|MyTiddler]]");
			expect(match).not.toBeNull();
			expect(match[1]).toBe("here");
			expect(match[2]).toBe("MyTiddler");
		});

		it("should match [[http://example.com]] as external", () => {
			const match = simplePattern.exec("abc [[http://example.com]]");
			expect(match).not.toBeNull();
			expect(match[1]).toBe("http://example.com");
		});

		it("should match [[Display|http://example.com]] as external with pipe", () => {
			const match = pipePattern.exec("abc [[Site|http://example.com]]");
			expect(match).not.toBeNull();
			expect(match[1]).toBe("Site");
			expect(match[2]).toBe("http://example.com");
		});

		it("should not match when brackets are unclosed", () => {
			expect(simplePattern.exec("abc [[MyTiddler")).toBeNull();
			expect(pipePattern.exec("abc [[here|MyTiddler")).toBeNull();
		});

		it("should not match empty target", () => {
			expect(simplePattern.exec("abc [[]]")).toBeNull();
			expect(pipePattern.exec("abc [[|Target]]")).toBeNull();
			expect(pipePattern.exec("abc [[Display|]]")).toBeNull();
		});

		it("should not match nested brackets", () => {
			expect(simplePattern.exec("abc [[a[b]c]]")).toBeNull();
			expect(pipePattern.exec("abc [[a|b[c]]]")).toBeNull();
		});

		it("should not match more than two opening brackets", () => {
			expect(simplePattern.exec("abc [[[MyTiddler]]")).toBeNull();
		});
	});

	describe("WIKITEXT_INLINE_MARK_RULES declarative config", () => {
		it("should expose the rule definitions", () => {
			expect(Array.isArray(WIKITEXT_INLINE_MARK_RULES)).toBe(true);
			expect(WIKITEXT_INLINE_MARK_RULES.length).toBeGreaterThan(0);
		});

		it("should include expected entries", () => {
			const names = WIKITEXT_INLINE_MARK_RULES.map((r) => r.name);
			expect(names).toContain("bold");
			expect(names).toContain("italic");
			expect(names).toContain("underline");
			expect(names).toContain("superscript");
			expect(names).toContain("subscript");
			expect(names).toContain("strikethrough");
			expect(names).toContain("code");
		});
	});

	describe("buildWikitextInlineRules", () => {
		it("should return wikilink rules when schema has link mark", () => {
			const schema = buildSchema();
			const rules = buildWikitextInlineRules(schema);
			expect(rules.length).toBeGreaterThanOrEqual(2);
		});

		it("should return mark rules for all configured prefixes", () => {
			const schema = buildSchema();
			const rules = buildWikitextInlineRules(schema);
			const markRuleCount = WIKITEXT_INLINE_MARK_RULES.filter((def) => schema.marks[def.markType]).length;
			// Plus 2 wikilink rules
			expect(rules.length).toBe(markRuleCount + 2);
		});

		it("should respect global disable via wiki mock", () => {
			const schema = buildSchema();
			const wiki = {
				getTiddlerText: function(title, defaultText) {
					if(title === "$:/config/prosemirror/wikitext-inline-inputrules") return "no";
					return defaultText;
				}
			};
			const rules = buildWikitextInlineRules(schema, { wiki: wiki });
			expect(rules.length).toBe(0);
		});

		it("should respect per-rule disable via wiki mock", () => {
			const schema = buildSchema();
			const wiki = {
				getTiddlerText: function(title, defaultText) {
					if(title === "$:/config/prosemirror/wikitext-inline-inputrules/bold") return "no";
					return defaultText;
				}
			};
			const rules = buildWikitextInlineRules(schema, { wiki: wiki });
			// All other rules still present, bold is missing
			const markRuleCount = WIKITEXT_INLINE_MARK_RULES.filter((def) => {
				if(def.name === "bold") return false;
				return !!schema.marks[def.markType];
			}).length;
			expect(rules.length).toBe(markRuleCount + 2);
		});
	});

});

test-prosemirror-keymap.js.text:
/*\
title: test-prosemirror-keymap.js
type: application/javascript
tags: [[$:/tags/test-spec]]

Tests ProseMirror keymap commands that can run without a browser EditorView.

\*/

"use strict";

describe("ProseMirror keymap commands", () => {

	let buildSchema, buildKeymap, EditorState, NodeSelection;
	try {
		buildSchema = require("$:/plugins/tiddlywiki/prosemirror/core/schema.js").buildSchema;
		buildKeymap = require("$:/plugins/tiddlywiki/prosemirror/core/keymap.js").buildKeymap;
		const prosemirrorState = require("prosemirror-state");
		EditorState = prosemirrorState.EditorState;
		NodeSelection = prosemirrorState.NodeSelection;
	} catch(e) {
		return;
	}

	function createSelectedWidgetParagraphState() {
		const schema = buildSchema();
		const widgetParagraph = schema.nodes.paragraph.create(null, schema.text('<<list-links "[tag[test]]">>'));
		const doc = schema.nodes.doc.create(null, [widgetParagraph]);
		return EditorState.create({
			schema: schema,
			doc: doc,
			selection: NodeSelection.create(doc, 0)
		});
	}

	function applyCommand(state, command) {
		let nextState = state;
		const handled = command(state, (tr) => {
			nextState = state.apply(tr);
		});
		return { handled: handled, state: nextState };
	}

	function expectParagraphInsertedAfterWidget(result, expectedSelectionType) {
		expect(result.handled).toBe(true);
		expect(result.state.doc.childCount).toBe(2);
		expect(result.state.doc.child(0).textContent).toBe('<<list-links "[tag[test]]">>');
		expect(result.state.doc.child(1).type.name).toBe("paragraph");
		expect(result.state.selection.constructor.name).toBe(expectedSelectionType || "TextSelection");
		expect(result.state.selection.from).toBeGreaterThan(result.state.doc.child(0).nodeSize - 1);
	}

	function createHardLineBreaksState(text, cursorOffset) {
		const schema = buildSchema();
		const block = schema.nodes.hard_line_breaks_block.create(null, schema.text(text));
		const doc = schema.nodes.doc.create(null, [block]);
		const TextSelection = require("prosemirror-state").TextSelection;
		return EditorState.create({
			schema: schema,
			doc: doc,
			selection: TextSelection.create(doc, 1 + cursorOffset)
		});
	}

	it("Enter inserts a paragraph after a selected rendered widget paragraph", () => {
		const state = createSelectedWidgetParagraphState();
		const keys = buildKeymap(state.schema);
		expect(typeof keys.Enter).toBe("function");
		expectParagraphInsertedAfterWidget(applyCommand(state, keys.Enter));
	});

	it("Shift-Enter inserts a paragraph after a selected rendered widget paragraph", () => {
		const state = createSelectedWidgetParagraphState();
		const keys = buildKeymap(state.schema);
		expect(typeof keys["Shift-Enter"]).toBe("function");
		expectParagraphInsertedAfterWidget(applyCommand(state, keys["Shift-Enter"]));
	});

	it("Enter does not handle a selected regular paragraph", () => {
		const schema = buildSchema();
		const paragraph = schema.nodes.paragraph.create(null, schema.text("ordinary text"));
		const doc = schema.nodes.doc.create(null, [paragraph]);
		const state = EditorState.create({
			schema: schema,
			doc: doc,
			selection: NodeSelection.create(doc, 0)
		});
		const keys = buildKeymap(schema);
		expect(keys.Enter(state, null)).toBe(false);
	});

	it("Enter inside hard-line-breaks block inserts a hard_break", () => {
		const state = createHardLineBreaksState("Line A", "Line A".length);
		const keys = buildKeymap(state.schema);
		const result = applyCommand(state, keys.Enter);
		expect(result.handled).toBe(true);
		expect(result.state.doc.child(0).type.name).toBe("hard_line_breaks_block");
		expect(result.state.doc.child(0).childCount).toBe(2);
		expect(result.state.doc.child(0).child(1).type.name).toBe("hard_break");
	});

	it("Shift-Enter at hard-line-breaks block start inserts a paragraph before", () => {
		const state = createHardLineBreaksState("Line A\nLine B", 0);
		const result = applyCommand(state, buildKeymap(state.schema)["Shift-Enter"]);
		expect(result.handled).toBe(true);
		expect(result.state.doc.childCount).toBe(2);
		expect(result.state.doc.child(0).type.name).toBe("paragraph");
		expect(result.state.doc.child(1).type.name).toBe("hard_line_breaks_block");
	});

	it("Shift-Enter at hard-line-breaks block end inserts a paragraph after", () => {
		const text = "Line A\nLine B";
		const state = createHardLineBreaksState(text, text.length);
		const result = applyCommand(state, buildKeymap(state.schema)["Shift-Enter"]);
		expect(result.handled).toBe(true);
		expect(result.state.doc.childCount).toBe(2);
		expect(result.state.doc.child(0).type.name).toBe("hard_line_breaks_block");
		expect(result.state.doc.child(1).type.name).toBe("paragraph");
	});

	it("Shift-Enter in hard-line-breaks block middle splits the block with a paragraph between", () => {
		const text = "Line A\nLine B\nLine C";
		const state = createHardLineBreaksState(text, "Line A\nLine B".length);
		const result = applyCommand(state, buildKeymap(state.schema)["Shift-Enter"]);
		expect(result.handled).toBe(true);
		expect(result.state.doc.childCount).toBe(3);
		expect(result.state.doc.child(0).type.name).toBe("hard_line_breaks_block");
		expect(result.state.doc.child(1).type.name).toBe("paragraph");
		expect(result.state.doc.child(2).type.name).toBe("hard_line_breaks_block");
	});

});

test-prosemirror-markdown-shortcuts.js.text:
/*\
title: test-prosemirror-markdown-shortcuts.js
type: application/javascript
tags: [[$:/tags/test-spec]]

Tests for Markdown shortcut enablement defaults in ProseMirror.

\*/

"use strict";

describe("ProseMirror markdown shortcut defaults", function() {
	let buildSchema, markdownShortcuts;
	try {
		buildSchema = require("$:/plugins/tiddlywiki/prosemirror/core/schema.js").buildSchema;
		markdownShortcuts = require("$:/plugins/tiddlywiki/prosemirror/features/markdown-shortcuts.js");
	} catch(e) {
		return;
	}

	function makeWiki(config) {
		return {
			getTiddlerText: function(title, defaultText) {
				return Object.prototype.hasOwnProperty.call(config, title) ? config[title] : defaultText;
			}
		};
	}

	it("should enable markdown shortcuts by default for markdown tiddlers", function() {
		const wiki = makeWiki({});
		expect(markdownShortcuts.shouldEnableMarkdownShortcuts(wiki, "text/markdown")).toBe(true);
		expect(markdownShortcuts.getMarkdownInputRules(wiki, buildSchema(), "text/markdown").length).toBeGreaterThan(0);
	});

	it("should keep markdown shortcuts disabled by default for wikitext tiddlers", function() {
		const wiki = makeWiki({});
		expect(markdownShortcuts.shouldEnableMarkdownShortcuts(wiki, "text/vnd.tiddlywiki")).toBe(false);
		expect(markdownShortcuts.getMarkdownInputRules(wiki, buildSchema(), "text/vnd.tiddlywiki").length).toBe(0);
	});

	it("should allow disabling markdown auto-shortcuts for markdown tiddlers", function() {
		const wiki = makeWiki({
			"$:/config/prosemirror/markdown-shortcuts/auto-for-markdown": "no"
		});
		expect(markdownShortcuts.shouldEnableMarkdownShortcuts(wiki, "text/x-markdown")).toBe(false);
	});

	it("should allow explicitly enabling markdown shortcuts for all editor types", function() {
		const wiki = makeWiki({
			"$:/config/prosemirror/markdown-shortcuts": "yes",
			"$:/config/prosemirror/markdown-shortcuts/auto-for-markdown": "no"
		});
		expect(markdownShortcuts.shouldEnableMarkdownShortcuts(wiki, "text/vnd.tiddlywiki")).toBe(true);
		expect(markdownShortcuts.getMarkdownInputRules(wiki, buildSchema(), "text/vnd.tiddlywiki").length).toBeGreaterThan(0);
	});
});

test-prosemirror-menu-elements.js.text:
/*\
title: test-prosemirror-menu-elements.js
type: application/javascript
tags: [[$:/tags/test-spec]]

Tests for menu-elements.js (EditorAction collection, snippet loading, etc.)
\*/

"use strict";

describe("ProseMirror menu-elements tests", () => {

	let getAllMenuElements, flattenMenuElementsWithGroup, getBuiltinActionCommands;
	let buildSchema, SlashMenuPlugin, SlashMenuKey, EditorState;
	try {
		const mod = require("$:/plugins/tiddlywiki/prosemirror/features/slash-menu/menu-elements.js");
		getAllMenuElements = mod.getAllMenuElements;
		flattenMenuElementsWithGroup = mod.flattenMenuElementsWithGroup;
		getBuiltinActionCommands = mod.getBuiltinActionCommands;
		buildSchema = require("$:/plugins/tiddlywiki/prosemirror/core/engine.js").buildSchema;
		const slashPlugin = require("$:/plugins/tiddlywiki/prosemirror/features/slash-menu/plugin.js");
		SlashMenuPlugin = slashPlugin.SlashMenuPlugin;
		SlashMenuKey = slashPlugin.SlashMenuKey;
		EditorState = require("prosemirror-state").EditorState;
	} catch(e) {
		// prosemirror dependencies not available in this test env
		return;
	}

	function makeSlashMenuView(triggerOptions) {
		const schema = buildSchema();
		const plugin = SlashMenuPlugin([{
			id: "paragraph",
			label: "Paragraph",
			type: "command",
			command: function() {}
		}], triggerOptions || { triggerKeys: ["/"] });
		const state = EditorState.create({
			schema: schema,
			doc: schema.nodes.doc.create(null, [schema.nodes.paragraph.create()]),
			plugins: [plugin]
		});
		return {
			plugin: plugin,
			state: state,
			dispatch: function(tr) {
				this.state = this.state.apply(tr);
			}
		};
	}

	describe("getBuiltinActionCommands", () => {

		it("should return an object with command functions", () => {
			const schema = buildSchema();
			const cmds = getBuiltinActionCommands(schema);
			expect(cmds).toBeDefined();
			expect(typeof cmds).toBe("object");
		});

		it("should have entries for common actions", () => {
			const schema = buildSchema();
			const cmds = getBuiltinActionCommands(schema);
			const expectedKeys = [
				"codeblock", "blockquote", "paragraph",
				"heading1", "heading2", "heading3", "heading4", "heading5", "heading6",
				"horizontal-rule", "bold", "italic", "underline", "strikethrough", "code-inline"
			];
			for(let i = 0; i < expectedKeys.length; i++) {
				expect(typeof cmds[expectedKeys[i]]).toBe("function",
					"Expected command for '" + expectedKeys[i] + "' to be a function");
			}
		});
	});

	describe("getAllMenuElements", () => {

		it("should return an array", () => {
			const schema = buildSchema();
			const elements = getAllMenuElements($tw.wiki, schema);
			expect(Array.isArray(elements)).toBe(true);
		});

		it("should include EditorAction tiddler-based elements", () => {
			const schema = buildSchema();
			const elements = getAllMenuElements($tw.wiki, schema);
			// Should have some action-* items from the editor-actions/*.tid files
			const actionItems = elements.filter((e) => e && e.id && e.id.startsWith("action-"));
			expect(actionItems.length).toBeGreaterThan(0);
		});

		it("should include block-type category items", () => {
			const schema = buildSchema();
			const elements = getAllMenuElements($tw.wiki, schema);
			const blockTypeItems = elements.filter((e) => e && e.category === "block-type" && e.type === "command");
			expect(blockTypeItems.length).toBeGreaterThan(0);
		});
	});

	describe("flattenMenuElementsWithGroup", () => {

		it("should flatten submenus into group headers + items", () => {
			const input = [
				{ id: "a", label: "A", type: "command", available: () => true },
				{
					id: "sub1", label: "Sub 1", type: "submenu", available: () => true,
					elements: [
						{ id: "b", label: "B", type: "command", available: () => true },
						{ id: "c", label: "C", type: "command", available: () => true }
					]
				}
			];
			const flat = flattenMenuElementsWithGroup(input);
			expect(flat.length).toBe(4); // a, group-sub1, b, c
			expect(flat[0].id).toBe("a");
			expect(flat[1].id).toBe("group-sub1");
			expect(flat[1].type).toBe("group");
			expect(flat[2].id).toBe("b");
			expect(flat[3].id).toBe("c");
		});

		it("should handle empty array", () => {
			expect(flattenMenuElementsWithGroup([]).length).toBe(0);
		});
	});

	describe("SlashMenuPlugin trigger matching", () => {
		it("should open for '/' even if the physical key code differs", () => {
			const view = makeSlashMenuView({ triggerKeys: ["/"] });
			const handled = view.plugin.props.handleKeyDown(view, {
				key: "/",
				code: "Digit7"
			});
			expect(handled).toBe(true);
			expect(SlashMenuKey.getState(view.state).open).toBe(true);
		});

		it("should not open for '#' even when it comes from the slash key position", () => {
			const view = makeSlashMenuView({ triggerKeys: ["/"] });
			const handled = view.plugin.props.handleKeyDown(view, {
				key: "#",
				code: "Slash"
			});
			expect(handled).toBe(false);
			expect(SlashMenuKey.getState(view.state).open).toBe(false);
		});
	});
});

test-prosemirror-widget-utils.js.text:
/*\
title: test-prosemirror-widget-utils.js
type: application/javascript
tags: [[$:/tags/test-spec]]

Tests parseWidget and parseAttributes from widget-block/utils.js.
These utilities parse <<macro "args">> invocations from user input.

\*/

"use strict";

describe("ProseMirror parseWidget tests", () => {

	let parseWidget, parseAttributes;
	try {
		const utils = require("$:/plugins/tiddlywiki/prosemirror/blocks/widget/utils.js");
		parseWidget = utils.parseWidget;
		parseAttributes = utils.parseAttributes;
	} catch(e) {
		return;
	}

	// --- Basic macro detection ---

	it("should parse a simple macro without args", () => {
		const result = parseWidget("<<myMacro>>");
		expect(result).not.toBeNull();
		expect(result.widgetName).toBe("myMacro");
	});

	it("should parse a macro with leading/trailing whitespace", () => {
		const result = parseWidget("  <<myMacro>>  ");
		expect(result).not.toBeNull();
		expect(result.widgetName).toBe("myMacro");
	});

	it("should return null for non-macro text", () => {
		expect(parseWidget("just text")).toBeNull();
		expect(parseWidget("")).toBeNull();
		expect(parseWidget("<single-bracket>")).toBeNull();
	});

	// --- Macro name validation ---

	it("should parse a macro with hyphens in name", () => {
		const result = parseWidget("<<list-links>>");
		expect(result).not.toBeNull();
		expect(result.widgetName).toBe("list-links");
	});

	it("should parse a macro with underscores in name", () => {
		const result = parseWidget("<<my_macro>>");
		expect(result).not.toBeNull();
		expect(result.widgetName).toBe("my_macro");
	});

	// --- Positional arguments ---

	it("should parse a single quoted positional argument", () => {
		const result = parseWidget('<<myMacro "hello world">>');
		expect(result).not.toBeNull();
		expect(result.attributes["0"]).toBe("hello world");
	});

	it("should parse a single-quoted positional argument", () => {
		const result = parseWidget("<<myMacro 'hello world'>>");
		expect(result).not.toBeNull();
		expect(result.attributes["0"]).toBe("hello world");
	});

	// --- Named arguments ---

	it("should parse named key=value arguments", () => {
		const result = parseWidget('<<myMacro key:"value">>');
		expect(result).not.toBeNull();
		expect(result.attributes.key).toBe("value");
	});

	// --- Critical: >> inside quoted strings ---

	it("should handle >> inside double-quoted attribute values", () => {
		const input = '<<myMacro "value with >> inside">>';
		const result = parseWidget(input);
		expect(result).not.toBeNull();
		expect(result.widgetName).toBe("myMacro");
		expect(result.attributes["0"]).toBe("value with >> inside");
	});

	it("should handle >> inside single-quoted attribute values", () => {
		const input = "<<myMacro 'value with >> inside'>>";
		const result = parseWidget(input);
		expect(result).not.toBeNull();
		expect(result.widgetName).toBe("myMacro");
		expect(result.attributes["0"]).toBe("value with >> inside");
	});

	// --- Critical: nested << >> ---

	it("should handle nested macros in attribute (triple-quote delimited)", () => {
		const input = '<<myMacro """<<innerMacro>>""">>';
		const result = parseWidget(input);
		expect(result).not.toBeNull();
		expect(result.widgetName).toBe("myMacro");
	});

	// --- TiddlyWiki filter syntax in arguments ---

	it("should parse filter argument with square brackets", () => {
		const input = '<<list-links "[tag[task]sort[title]]">>';
		const result = parseWidget(input);
		expect(result).not.toBeNull();
		expect(result.widgetName).toBe("list-links");
		expect(result.attributes["0"]).toBe("[tag[task]sort[title]]");
		expect(result.orderedAttributes[0].name).toBe("0");
		expect(result.orderedAttributes[0].quoted).toBe(true);
	});

	// --- Complex real-world cases ---

	it("should parse macro with multiple arguments", () => {
		const input = '<<myMacro "arg1" key:"val2">>';
		const result = parseWidget(input);
		expect(result).not.toBeNull();
		expect(result.widgetName).toBe("myMacro");
		expect(result.attributes["0"]).toBe("arg1");
		expect(result.attributes.key).toBe("val2");
	});

	it("should parse a macro with colon-delimited named args", () => {
		const input = '<<image-picker actions:"<$action-sendmessage $message=\'test\'/>"  >>';
		const result = parseWidget(input);
		expect(result).not.toBeNull();
		expect(result.widgetName).toBe("image-picker");
	});

	// --- parseAttributes edge cases ---

	it("should parse empty attributes string", () => {
		const result = parseAttributes("");
		expect(Object.keys(result).length).toBe(0);
	});

	it("should parse null/undefined attributes", () => {
		const result = parseAttributes(null);
		expect(Object.keys(result).length).toBe(0);
	});

	it("should parse unquoted positional values", () => {
		const result = parseAttributes("hello");
		expect(result["0"]).toBe("hello");
	});
});
